import type { VNode } from 'vue'
import { vShow } from 'vue'

export function isNodeVShowFalse(vNode: VNode): boolean {
  const showDir = vNode.dirs?.find(({ dir }) => dir === vShow)
  return !!(showDir && showDir.value === false)
}

const refs = ref<(T | undefined)[]>([]) as Ref<(T | undefined)[]>

  onBeforeUpdate(() => (refs.value = []))

  function updateRef (e: any, i: number) {
    refs.value[i] = e
  }

const unrefFn = options?.computedGetter === false ? unref : toValue
  return function (this: any, ...args: any[]) {
    return computed(() => fn.apply(this, args.map(i => unrefFn(i))))
  } as ReactifyReturn<T, K>

export const useEditThisPageOnGithub = () => {
  const url = useThisPageOnGithub()
  return computed(() => url.value.replace('/tree/', '/edit/'))
}

